var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。`,ENG:`that you'll be with it, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called it to your office. It said it'd be here soon.`,TWN:`做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`HOUND_SL_NULL_NULL`,text:{KOREA:`귀하의 종신계약 권유에 대한 답을 산출하는 중.`,JPN:`終身契約勧誘への回答を算出中。`,ENG:`Looking for an appropriate answer to your lifetime contract offer...`,TWN:`正在計算對於「終身契約」提案的答覆。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HOUND_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`HOUND_SL_NULL_NULL`,text:{KOREA:`귀사에 편입된 후로, 교전 능력의 지속적인 향상을 확인.`,JPN:`貴社への編入以降、交戦能力が持続的に向上していることを確認。`,ENG:`My combat capacity has continuously improved since I joined your company.`,TWN:`確認加入貴公司後，作戰能力獲得了持續性的改善。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HOUND_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`HOUND_SL_NULL_NULL`,text:{KOREA:`조건 문제 없음. 종신계약 제안을 승낙하겠다.`,JPN:`条件に問題なし。終身契約の提案を承諾するものとする。`,ENG:`All conditions acceptable. I accept your lifetime contract offer.`,TWN:`對條件沒有異議。接受終身契約提案。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HOUND_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};